#include <stdio.h>
int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    const int sum = 12; // 6 + 6
    for(int i=0;i<T;++i){
        printf("%d", sum);
        if(i+1<T) printf("\\n");
    }
    return 0;
}

